The code below creates a complete, self-contained HTML file. It uses **Three.js** to render a 3D scene containing a house.

### How to use this:
1.  Copy the code block below.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model (Drag to rotate, Scroll to zoom)</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x555555 }); // Grey
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0xADD8E6, transparent: true, opacity: 0.6 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x333333 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, grassMaterial);
        floor.position.y = 0;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Main Body
        const bodyGeo = new THREE.BoxGeometry(8, 6, 8);
        const body = new THREE.Mesh(bodyGeo, wallMaterial);
        body.position.y = 3;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // Roof
        const roofGeo = new THREE.ConeGeometry(7, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4; // Rotate to align with box
        roof.castShadow = true;
        roof.receiveShadow = true;
        houseGroup.add(roof);

        // Windows
        const windowGeo = new THREE.BoxGeometry(1.5, 1.5, 0.2);

        // Front Windows
        const win1 = new THREE.Mesh(windowGeo, windowMaterial);
        win1.position.set(1.5, 4, 4.1);
        houseGroup.add(win1);

        const win2 = new THREE.Mesh(windowGeo, windowMaterial);
        win2.position.set(-1.5, 4, 4.1);
        houseGroup.add(win2);

        // Side Window
        const win3 = new THREE.Mesh(windowGeo, windowMaterial);
        win3.position.set(4.1, 4, 1.5);
        houseGroup.add(win3);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.5);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 2, 4.25);
        houseGroup.add(door);

        // Chimney
        const chimneyGeo = new THREE.BoxGeometry(1, 3, 1);
        const chimney = new THREE.Mesh(chimneyGeo, roofMaterial);
        chimney.position.set(3, 10, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### Features included in this code:
*   **3D Geometry:** Uses `BoxGeometry` for walls and `ConeGeometry` for the roof.
*   **Lighting:** Includes ambient light for base visibility and a directional light (sun) that casts realistic shadows.
*   **Materials:** Different colors for walls, roof, windows, and grass.
*   **Interactivity:** Uses `OrbitControls`, allowing you to click and drag to rotate around the house and scroll to zoom in/out.
*   **Responsive:** The canvas automatically resizes if you change the browser window size.
